import './ToggleDark.css';
import React, { Component } from 'react';

class ToggleSwitch extends Component {
  state = {
    isDark: true,
  };
  handleChange = ev => {
    this.setState({
      isDark: ev.target.checked,
    });

    document.body.className = ev.target.checked ? 'dark' : 'light';
  };

  render = () => {
    return (
      <div className="neumorphism-toggle">
        <input
          type="checkbox"
          id="neumorphism"
          checked={this.state.isDark}
          onChange={this.handleChange}
        />
        <label htmlFor="neumorphism">
          <div className="switch">
            <div className="dot"></div>
          </div>
          <span>{this.state.isDark ? 'Dark' : 'Light'}mode</span>
        </label>
      </div>
    );
  };
}

export default ToggleSwitch;
