import React, { Component } from 'react';
import './App.css';

const padNum = num => ('0' + num).slice(-2);

class App extends Component {
  state = {
    finalDate: new Date('07/08/2021 14:40:00 GMT+0200'), // MM/DD/YYYY
  };
  setTime = () => {
    const totalSeconds = (this.state.finalDate.getTime() - Date.now()) / 1000;
    const days = Math.floor(totalSeconds / (60 * 60 * 24));
    const hours = padNum(
      Math.floor((totalSeconds % (60 * 60 * 24)) / (60 * 60))
    );
    const minutes = padNum(Math.floor((totalSeconds % (60 * 60)) / 60));
    const seconds = padNum(Math.floor(totalSeconds % 60));
    this.setState({
      days,
      hours,
      minutes,
      seconds,
    });
    this.timeout = setTimeout(this.setTime, this.getTimeToNextSecond());
  };
  getTimeToNextSecond = () => {
    const dateTimeNextSecond = new Date();
    dateTimeNextSecond.setSeconds(dateTimeNextSecond.getSeconds() + 1, 0);
    return dateTimeNextSecond.getTime() - Date.now();
  };
  componentDidMount = () => {
    this.setTime();
    this.timeout = setTimeout(this.setTime, this.getTimeToNextSecond());
  };
  render = () => {
    return (
      <div className="App">
        <main className="App-main">
          <span>
            <span className="special">{this.state.days}</span>
            {' days, '}
            <span className="special">{this.state.hours}</span>
            {' hours, '}
            <span className="special">{this.state.minutes}</span>
            {' minutes and '}
            <span className="special">{this.state.seconds}</span>
            {' seconds until '}
            <span className="special">summer holidays</span>
          </span>
        </main>
      </div>
    );
  };
}

export default App;
